const MAX_ROWS = 600

if (msg.topic === "clear-log") {
    context.set('log', [])
    msg.topic = ''
    msg.payload = []
    return msg
}

const incomingMessage = msg.payload
let log = context.get('log') || []
if (!Array.isArray(log)) {
    log = []
